import{_ as a,o as i,c as o,ag as n}from"./chunks/framework.ByAj6Cie.js";const u=JSON.parse('{"title":"Armónicos","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-quality/harmonics.md","filePath":"es/power-quality/harmonics.md"}'),s={name:"es/power-quality/harmonics.md"};function r(l,e,c,t,d,p){return i(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="armonicos" tabindex="-1">Armónicos <a class="header-anchor" href="#armonicos" aria-label="Permalink to &quot;Armónicos&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Los armónicos son componentes de voltaje o corriente que ocurren en múltiplos de la frecuencia fundamental del sistema de potencia.</p><p>Distorsionan la forma de onda sinusoidal ideal y son causados principalmente por cargas no lineales.</p><p>Los armónicos son un problema común de calidad de energía en sistemas industriales modernos con uso extendido de electrónica de potencia.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Comprender los armónicos es importante para:</p><ul><li>Mantener una operación eficiente y estable de los sistemas eléctricos</li><li>Prevenir sobrecalentamiento de equipos y conductores</li><li>Evitar el mal funcionamiento de dispositivos sensibles</li><li>Reducir pérdidas y mejorar la calidad de energía</li></ul><p>La gestión de armónicos ayuda a proteger tanto el equipo como el desempeño del sistema.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>En un sistema ideal, la corriente y el voltaje siguen una forma de onda sinusoidal pura a la frecuencia fundamental.</p><p>Las cargas no lineales consumen corriente de manera no sinusoidal, creando componentes de frecuencia adicionales.</p><p>Estos componentes se denominan armónicos y ocurren en múltiplos enteros de la frecuencia base:</p><ul><li>2.º armónico, 3.º armónico, 5.º armónico, y así sucesivamente</li></ul><p>Las fuentes comunes de armónicos incluyen:</p><ul><li>Variadores de frecuencia</li><li>Fuentes de alimentación y rectificadores</li><li>Sistemas UPS</li><li>Iluminación LED y equipos electrónicos</li></ul><p>Estas corrientes armónicas circulan por el sistema e interactúan con la impedancia, causando distorsión de voltaje.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Los armónicos son relevantes en:</p><ul><li>Instalaciones industriales con gran cantidad de variadores y convertidores</li><li>Centros de datos y entornos con alta densidad de equipos electrónicos</li><li>Sistemas de automatización con equipos de control sensibles</li><li>Instalaciones con cargas no lineales significativas</li><li>Sistemas de potencia que requieren alta calidad de energía</li></ul><p>Están presentes en la mayoría de las instalaciones eléctricas modernas.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Orden armónico</strong><br> Los armónicos de orden bajo tienden a tener mayor impacto en el sistema</p></li><li><p><strong>Nivel de distorsión total</strong><br> El efecto combinado de todos los armónicos determina el impacto general</p></li><li><p><strong>Impedancia del sistema</strong><br> Influye en cómo los armónicos afectan la distorsión de voltaje</p></li><li><p><strong>Condiciones de resonancia</strong><br> Pueden amplificar los niveles armónicos y crear problemas severos</p></li><li><p><strong>Sensibilidad del equipo</strong><br> Algunos dispositivos se ven más afectados por la distorsión de la forma de onda</p></li><li><p><strong>Métodos de mitigación</strong><br> Filtros, reactores y un diseño adecuado del sistema reducen los armónicos</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>Los variadores son una de las principales fuentes de armónicos en sistemas industriales</li><li>Los armónicos pueden causar sobrecalentamiento en transformadores y conductores de neutro</li><li>Los bancos de capacitores pueden interactuar con armónicos y crear resonancia</li><li>Un diseño adecuado del sistema reduce la propagación de armónicos</li><li>La medición es esencial para identificar problemas armónicos y sus fuentes</li></ul>',25)])])}const f=a(s,[["render",r]]);export{u as __pageData,f as default};
